<template>
	<div class="main">
		<el-dialog title="上传合同" :visible.sync="dialogVisible" width="500px" :show-close="false" destroy-on-close
			:before-close="beforeClose">
			<el-descriptions :column="2" border labelStyle="width:80px;" style="width: 450px;margin-bottom: 10px;">
				<el-descriptions-item>
					<template slot="label">
						订单号
					</template>
					{{info.id}}
				</el-descriptions-item>
				<el-descriptions-item>
					<template slot="label">
						租期
					</template>
					{{info.duration}}
				</el-descriptions-item>
				<el-descriptions-item>
					<template slot="label">
						房东ID
					</template>
					{{info.user}}
				</el-descriptions-item>
				<el-descriptions-item>
					<template slot="label">
						发起时间
					</template>
					{{info.orderTime}}
				</el-descriptions-item>
			</el-descriptions>
			<div style="width: 450px;">
				<el-upload drag :action="uploadPath" :data="uploaddata" :on-success="onUploadSuccess"
					style="margin-left: 55px;">
					<i class="el-icon-upload"></i>
					<div class="el-upload__text">将文件拖到此处，或<em>点击上传</em></div>
				</el-upload>
			</div>
			<span slot="footer">
				<el-button @click="onClickCancelContract">取 消</el-button>
				<el-button type="primary" @click="onConfirmContract">确 定</el-button>
			</span>
		</el-dialog>


		<div class="order_container">
			<div style="font-size: 20px;margin-bottom: 20px;">我管理的订单</div>
			<div style="margin-bottom: 20px;">
				<el-radio-group @change="refreshOrder" size="medium" v-model="query.status">
					<el-radio-button label="全部"></el-radio-button>
					<el-radio-button label="未确认"></el-radio-button>
					<el-radio-button label="已确认"></el-radio-button>
					<el-radio-button label="已生效"></el-radio-button>
					<el-radio-button label="已取消"></el-radio-button>
				</el-radio-group>
				<el-input style="width: 400px;float: right;margin-right: 37px;" @change="refreshOrder"
					placeholder="搜索订单号/房东/房源ID..." v-model="query.queryString">
					<el-button slot="append" icon="el-icon-search"></el-button>
				</el-input>
			</div>
			<div>
				<div v-for="(item,index) in orderData">
					<div class="ordercard"
						style="height: 262px;width: 1023px;float: left; margin-bottom: 20px;margin-right: 20px; box-shadow: 0 2px 12px 0 rgba(0,0,0,0.1);">
						<div style="width: fit-content;float: left;" class="info">
							<transition name="el-zoom-in-center">
								<one-house v-if="show" :index="index"></one-house>
							</transition>
						</div>
						<div style="float: left;height: 100%;width: calc(100% - 242px)">
							<el-descriptions :column="2" border labelStyle="width:100px;" contentStyle="width:200px">
								<el-descriptions-item>
									<template slot="label">
										租期
									</template>
									<el-tag><b>{{item.duration}}</b></el-tag> 个月
								</el-descriptions-item>
								<el-descriptions-item>
									<template slot="label">
										状态
									</template>
									<b>
										<el-tag type="warning" v-if="item.orderStatus==0">待确认</el-tag>
										<el-tag v-if="item.orderStatus==1">已确认</el-tag>
										<el-tag type="success" v-if="item.orderStatus==2">已生效</el-tag>
										<el-tag type="info" v-if="item.orderStatus==3">已取消</el-tag>
									</b>
								</el-descriptions-item>
								<el-descriptions-item>
									<template slot="label">
										订单号
									</template>
									{{item.id}}
								</el-descriptions-item>
								<el-descriptions-item>
									<template slot="label">
										下单时间
									</template>
									{{item.orderTime}}
								</el-descriptions-item>
								<el-descriptions-item>
									<template slot="label">
										房客ID
									</template>
									{{userData[index].id}}
								</el-descriptions-item>
								<el-descriptions-item>
									<template slot="label">
										房客用户名
									</template>
									{{userData[index].username}}
								</el-descriptions-item>
								<el-descriptions-item>
									<template slot="label">
										房客姓名
									</template>
									{{userData[index].name}}
								</el-descriptions-item>
								<el-descriptions-item>
									<template slot="label">
										房客手机号
									</template>
									{{userData[index].phone}}
								</el-descriptions-item>
							</el-descriptions>
							<!-- <div style="height: 155px;"></div> -->
							<div style="padding:15px 10px 0 10px;">
								<el-button v-if="item.orderStatus==0" type="success" style="float: right;"
									@click="onClickConfirmOrder(item.id,item.houseId)">确认订单</el-button>
								<el-button v-if="item.orderStatus==1" type="primary" style="float: right;"
									@click="onClickUploadContract(item)">上传合同</el-button>
							</div>
						</div>
					</div>
				</div>
			</div>
		</div>
	</div>
</template>

<script>
	import OneHouse from '../components/OneHouse.vue'
	export default {
		created() {
			this.$emit('changeIndex', '订单管理')
		},
		activated() {
			this.show = false
			this.$axios.post(this.common.backendURL + '/api/order/listOrders', {
				queryString: this.query.queryString,
				status: this.query.status == '未确认' ? 0 : this.query.status == '已确认' ? 1 : this.query.status == '已生效' ? 2 :
					this.query.status == '已取消' ? 3 : 4
			}).then(res => {
				this.orderData = res.data.orders
				this.housesData = res.data.houses
				this.userData = res.data.users
				this.show = true
			})
		},
		data() {
			return {
				name: 'OrderManagement',
				query: {
					queryString: '',
					status: '全部',

				},
				orderData: [],
				housesData: [],
				userData: [],
				show: false,
				dialogVisible: false,
				// uploadPath: 'https://peirong.co:8443/EasyDrive/file/upload',
				uploadPath: 'http://192.168.1.102:8080/file/upload',
				data: {
					uploadContractId: null,
					uploadFilePath: null
				},
				uploaddata: {
					owner: 10003,
					path: '/'
				},
				info: { //对话框中显示的当前订单的信息
					id: null,
					duration: 0,
					user: '',
					orderTime: ''
				}
			}
		},
		methods: {
			refreshOrder() {
				this.show = false
				this.$axios.post(this.common.backendURL + '/api/order/listOrders', {
					queryString: this.query.queryString,
					status: this.query.status == '未确认' ? 0 : this.query.status == '已确认' ? 1 : this.query.status == '已生效' ? 2 :
						this.query.status == '已取消' ? 3 : 4
				}).then(res => {
					this.orderData = res.data.orders
					this.housesData = res.data.houses
					this.userData = res.data.users
					this.show = true
				})
			},
			onClickConfirmOrder(orderId, houseId) {
				// 修改订单状态为已确认，锁定所有其他相关订单
				this.$axios.get(this.common.backendURL + '/api/order/confirmOrder?orderId=' + orderId + '&houseId=' + houseId)
					.then(res => {
						if (res.data.code == 1) {
							this.refreshOrder()
							this.$message.success('确认成功，请上传合同文件')
						} else {
							this.$message.error('确认失败，服务器错误')
						}
					})
			},
			onClickUploadContract(order) {
				this.data.uploadContractId = order.id
				this.info.id = order.id
				this.info.duration = order.duration
				this.info.user = order.userId
				this.info.orderTime = order.orderTime
				this.dialogVisible = true
			},
			onUploadSuccess(response) {
				//提示上传失败与否
				if (response.code == 200) {
					this.data.uploadFilePath = response.filepath
					this.$message.success('上传成功'+response.filepath)
				} else {
					this.$message.error('上传失败')
				}
			},
			onConfirmContract() {
				//写入订单合同路径，修改订单状态，写入process记录
				this.$axios.get(this.common.backendURL + '/api/order/confirmContract?contract=' + this.data.uploadFilePath + '&orderId=' +
						this.data.uploadContractId)
					.then(res => {
						if (res.data.code == 1) {
							
							this.$message.success('订单已生效')
							this.refreshOrder()
							this.dialogVisible = false
						} else {
							this.$message.error('上传失败，服务器错误')
						}
					})
			},
			beforeClose() {
				this.data.uploadContractId = null
				this.data.uploadFilePath = null
			},
			onClickCancelContract() {
				//删除上传的文件
				this.dialogVisible = false
			}

		},
		components: {
			OneHouse
		}
	}
</script>

<style scoped>
	.el-upload-dragger {
		width: 400px !important;
		margin-left: 50px;
	}

	.main {
		width: 1060px;
		margin: 0 auto;
	}

	.info {
		transition: 0.3s;
		/* 设置变换的过渡时间为0.3秒 */
	}

	.info:hover {
		/* 当鼠标悬停在图片上时 */
		transform: scale(1.1);
		/* 让图片放大1.1倍 */
	}
</style>